import { useMemo } from 'react';
import { useInfiniteQuery } from '@tanstack/react-query';

import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { TransactionDTO } from 'Repositories/transactions/types/TransactionDTO';
import { requestClient } from 'Shared/requestClient/requestClient';
import { RequestListDataT } from 'Shared/types/api/RequestListDataT';
import { useGlobalValue } from 'Shared/store/useGlobalValue';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { IdsListKeyE } from 'Shared/types/IdsListKeyE';

import { TransactionFiltersT } from '../../pages/transactions/filter/TransactionFiltersT';
import { SortOrderE } from 'Shared/types/SortOrderE';

export const useTransactionList = (
  search: string,
  filters: TransactionFiltersT,
  sortOrder: SortOrderE,
) => {
  const deletedTransactionsIds = useGlobalValue(GlobalStoreFieldE.IDS_LIST)[
    IdsListKeyE.DELETED_TRANSACTIONS
  ];

  const preparedResult = useInfiniteQuery<RequestListDataT<TransactionDTO>>({
    queryKey: [ApiGatewayE.BANK_TRANSACTIONS, search, filters, sortOrder],
    initialPageParam: 1,
    queryFn: async ({ pageParam = 1 }) => {
      const page = pageParam as number;

      const params: Record<string, string | number> = {
        searchTerm: search,
        page,
        pageSize: 100,
        sortOrder,
      };

      if (filters.from) {
        params['date[gte]'] = filters.from;
      }

      if (filters.to) {
        params['date[lte]'] = filters.to;
      }

      if (filters.bankAccountIds && filters.bankAccountIds.length) {
        params['bankAccountId[in]'] = filters.bankAccountIds.join(',');
      }

      if (filters.categoryIds && filters.categoryIds.length) {
        params['categories[in]'] = filters.categoryIds.join(',');
      }

      const response = await requestClient.get<
        RequestListDataT<TransactionDTO>
      >(ApiGatewayE.BANK_TRANSACTIONS, undefined, params);

      return response;
    },
    getNextPageParam: lastPage => {
      if (lastPage.page < lastPage.totalPages) {
        return lastPage.page + 1;
      }

      return undefined;
    },
  });

  const transactions = useMemo(() => {
    const pages = preparedResult.data?.pages ?? [];

    const all = pages.flatMap(page => page.results);

    return all.filter(
      transaction => !deletedTransactionsIds?.includes(transaction.id),
    );
  }, [deletedTransactionsIds, preparedResult.data?.pages]);

  return {
    loading: preparedResult.isLoading && !preparedResult.isFetchingNextPage,
    transactions,
    fetchNextPage: preparedResult.fetchNextPage,
    hasNextPage: preparedResult.hasNextPage ?? false,
    isFetchingNextPage: preparedResult.isFetchingNextPage,
  };
};

