     1→import { useCallback, useReducer } from 'react';
     2→
     3→import useCancellablePromise from 'Shared/hooks/useCancellablePromise';
     4→
     5→const REQUEST_DATA = 'request_data';
     6→const REQUEST_DATA_SUCCESS = 'request_data_success';
     7→const REQUEST_DATA_FAILURE = 'request_data_failure';
     8→const RESET = 'reset';
     9→
    10→type State<T> = {
    11→  data: T | null;
    12→  error: unknown;
    13→  loading: boolean;
    14→};
    15→
    16→type Action<T> =
    17→  | { type: typeof REQUEST_DATA }
    18→  | { type: typeof REQUEST_DATA_SUCCESS; payload: T }
    19→  | { type: typeof REQUEST_DATA_FAILURE; payload: unknown }
    20→  | { type: typeof RESET };
    21→
    22→const INITIAL_RESPONSE_STATE: State<unknown> = {
    23→  data: null,
    24→  error: null,
    25→  loading: false,
    26→};
    27→
    28→function reducer<T>(state: State<T>, action: Action<T>): State<T> {
    29→  switch (action.type) {
    30→    case REQUEST_DATA:
    31→      return { ...state, loading: true };
    32→
    33→    case REQUEST_DATA_SUCCESS:
    34→      return { ...state, data: action.payload, loading: false };
    35→
    36→    case REQUEST_DATA_FAILURE:
    37→      return { data: null, error: action.payload, loading: false };
    38→
    39→    case RESET:
    40→      return { ...INITIAL_RESPONSE_STATE } as State<T>;
    41→
    42→    default:
    43→      throw new Error('Unknown action');
    44→  }
    45→}
    46→
    47→function useAsyncFn<P extends unknown[], T>(
    48→  fn: (...args: P) => T | Promise<T>,
    49→) {
