import React, { useRef } from 'react';
import {
  useForm,
  FormProvider,
  SubmitHandler,
  FieldValues,
  DefaultValues,
  Path,
} from 'react-hook-form';
import { AxiosError } from 'axios';

import { ValidationError } from 'Shared/errors/ValidationError';
import { notificationService } from 'Services/notificationService';
import { AuFormOnSubmitT } from 'Components/form/AuFormOnSubmitT';
import { errorReporter } from 'Shared/utils/errorReporter';
import { useDidMount } from 'Shared/hooks/useDidMount';
import { AuFormOnChangeT } from 'Components/form/AuFormOnChangeT';
import useChanged from 'Shared/hooks/useChanged';

type MyFormProps<T extends FieldValues> = {
  className?: string;
  id?: string;
  defaultValues?: DefaultValues<T>;
  onChange?: AuFormOnChangeT<T>;
  onSubmit: AuFormOnSubmitT<T>;
  children: React.ReactNode;
};

export const AuForm = <T extends FieldValues>({
  className,
  id,
  defaultValues,
  onChange,
  onSubmit,
  children,
}: MyFormProps<T>) => {
  const formMethods = useForm({
    defaultValues,
    reValidateMode: 'onBlur',
  });

  const handleSubmit: SubmitHandler<T> = async (data, event) => {
    try {
      await onSubmit(data, event);
    } catch (error) {
      if (error instanceof ValidationError) {
        error.fieldErrors.forEach(fieldError => {
          formMethods.setError(fieldError.path as Path<T>, {
            type: 'manual',
            message: fieldError.msg,
          });
        });

        const fieldOrder = React.Children.toArray(children).flatMap(child => {
          if (
            React.isValidElement(child) &&
            typeof child.props === 'object' &&
            child.props !== null &&
            'name' in child.props
          ) {
            return [child.props.name];
          }

          return [];
        });

        const firstErrorFieldNameInDOM = fieldOrder.find(name =>
          error.fieldErrors.some(f => f.path === name),
        );

        if (firstErrorFieldNameInDOM) {
          formMethods.setFocus(firstErrorFieldNameInDOM as Path<T>);
        }

        return;
      }

      if (error instanceof Error || error instanceof AxiosError) {
        notificationService.addAlert(error.message);
      }

      errorReporter.report('Form submit error:', error);
    }
  };

  const formRef = useRef<HTMLFormElement | null>(null);

  useDidMount(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        e.key === 'Enter' &&
        formRef.current &&
        formRef.current.contains(document.activeElement)
      ) {
        const inputs = Array.from(
          formRef.current.querySelectorAll<HTMLInputElement>('input'),
        );
        const activeElement = document.activeElement as HTMLInputElement;

        if (
          inputs.length > 0 &&
          inputs[inputs.length - 1] === activeElement &&
          activeElement.value.trim() !== ''
        ) {
          e.preventDefault();

          formMethods.handleSubmit(handleSubmit)();
        }
      }
    };

    if (formRef.current) {
      formRef.current.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      if (formRef.current) {
        formRef.current.removeEventListener('keydown', handleKeyDown);
      }
    };
  });

  const watchedData = formMethods.watch();

  const watchDataChanged = useChanged(watchedData);

  React.useEffect(() => {
    if (watchDataChanged && onChange) {
      onChange(watchedData);
    }
  }, [watchDataChanged, watchedData, onChange]);

  return (
    <form
      ref={formRef}
      id={id}
      className={className}
      onSubmit={formMethods.handleSubmit(handleSubmit)}
    >
      {/* eslint-disable-next-line react/jsx-props-no-spreading */}
      <FormProvider {...formMethods}>{children}</FormProvider>
    </form>
  );
};

